package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class JsonWriterTest {

  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  void testSetLenientTrue() throws NoSuchFieldException, IllegalAccessException {
    jsonWriter.setLenient(true);

    Field lenientField = JsonWriter.class.getDeclaredField("lenient");
    lenientField.setAccessible(true);
    boolean lenientValue = (boolean) lenientField.get(jsonWriter);

    assertTrue(lenientValue);
  }

  @Test
  void testSetLenientFalse() throws NoSuchFieldException, IllegalAccessException {
    jsonWriter.setLenient(false);

    Field lenientField = JsonWriter.class.getDeclaredField("lenient");
    lenientField.setAccessible(true);
    boolean lenientValue = (boolean) lenientField.get(jsonWriter);

    assertFalse(lenientValue);
  }
}
